import { EditOutlined, TeamOutlined, UserOutlined } from '@ant-design/icons';
import { Avatar, Form, Input, Select, Typography } from 'antd';
import React, { memo, useEffect } from 'react';

import CompoundModal from '@/components/ui/CompoundModal';
import { INTERNSHIP_MANAGEMENT_UI } from '@/constants/internship-management/internship-management';

const { Text } = Typography;

export const CreateGroupModal = memo(
  ({
    open,
    group = null,
    initialStudents = [],
    students = [],
    loadingStudents = false,
    onCancel,
    onFinish,
  }) => {
    const [form] = Form.useForm();
    const { CREATE } = INTERNSHIP_MANAGEMENT_UI.GROUP_MANAGEMENT.MODALS;
    const isEdit = !!group;

    useEffect(() => {
      if (open) {
        form.resetFields();
        if (isEdit) {
          form.setFieldsValue({
            name: group.name,
            track: group.track?.toUpperCase() || 'FRONTEND',
          });
        } else if (initialStudents.length > 0) {
          const ids = initialStudents.map(
            (s) => s.studentId || s.StudentId || s.id || s.applicationId
          );
          console.log('MODAL INITIAL IDS:', ids);
          form.setFieldsValue({
            name: `${CREATE.DEFAULT_NAME_PREFIX}${Math.floor(Math.random() * 1000)}`,
            studentIds: ids,
          });
        }
      }
    }, [open, form, group, isEdit, initialStudents]);

    const handleCancel = () => {
      onCancel();
    };

    const handleFinish = (values) => {
      // ─Éß║úm bß║úo studentIds lu├┤n c├│ dß╗» liß╗çu, thß╗¡ mß╗ìi thuß╗Öc t├¡nh ID c├│ thß╗â
      const ids =
        values.studentIds && values.studentIds.length > 0
          ? values.studentIds
          : initialStudents.map((s) => s.studentId || s.StudentId || s.id || s.applicationId);

      console.log('MODAL FINISH IDS:', ids);

      const payload = {
        ...values,
        studentIds: ids,
      };
      // backend expects studentIds for creation
      onFinish(payload);
      form.resetFields();
    };

    const studentOptions = students.map((s) => ({
      label: (
        <div className="flex items-center gap-2 py-1">
          <Avatar size="small" src={s.avatar} icon={<UserOutlined />} />
          <div className="flex flex-col leading-tight">
            <Text className="text-xs font-bold">
              {s.studentFullName || s.name || s.fullName || 'Unknown Student'}
            </Text>
            <Text className="text-muted text-[10px] uppercase opacity-60">
              {s.studentCode || s.code || 'No Code'} {CREATE.BULLET} {s.major || 'No Major'}
            </Text>
          </div>
        </div>
      ),
      value: s.studentId || s.StudentId || s.id || s.applicationId,
      searchValue: `${s.studentFullName || ''} ${s.name || ''} ${s.studentCode || ''}`,
    }));

    return (
      <CompoundModal open={open} onCancel={handleCancel} width={580} destroyOnHidden>
        <CompoundModal.Header
          icon={<TeamOutlined />}
          title={isEdit ? CREATE.TITLE_EDIT : CREATE.TITLE}
          subtitle={isEdit ? CREATE.SUBTITLE_EDIT : CREATE.SUBTITLE}
        />

        <Form
          form={form}
          layout="vertical"
          onFinish={handleFinish}
          className="p-6 pt-8"
          requiredMark={false}
        >
          <Form.Item
            label={
              <span className="text-text text-xs font-bold tracking-wider uppercase">
                {CREATE.NAME_LABEL}
              </span>
            }
            name="name"
            rules={[{ required: true, message: CREATE.NAME_REQUIRED }]}
          >
            <Input
              prefix={<EditOutlined className="text-muted" />}
              placeholder={CREATE.NAME_PLACEHOLDER}
              className="bg-surface border-border h-11 rounded-xl"
            />
          </Form.Item>

          <div className="grid grid-cols-2 gap-4">
            <Form.Item
              label={
                <span className="text-text text-xs font-bold tracking-wider uppercase">
                  {CREATE.TRACK_LABEL}
                </span>
              }
              name="track"
              initialValue="FRONTEND"
              rules={[{ required: true, message: CREATE.TRACK_REQUIRED }]}
            >
              <Select
                className="h-11 w-full rounded-xl"
                options={[
                  { label: CREATE.TRACK_OPTIONS.FRONTEND, value: 'FRONTEND' },
                  { label: CREATE.TRACK_OPTIONS.BACKEND, value: 'BACKEND' },
                  { label: CREATE.TRACK_OPTIONS.MOBILE, value: 'MOBILE' },
                  { label: CREATE.TRACK_OPTIONS.DESIGN, value: 'DESIGN' },
                ]}
              />
            </Form.Item>

            {!isEdit && (
              <Form.Item
                label={
                  <span className="text-text text-xs font-bold tracking-wider uppercase">
                    {CREATE.STUDENTS_LABEL}
                  </span>
                }
                name="studentIds"
                rules={[{ required: true, message: CREATE.STUDENTS_REQUIRED }]}
              >
                <Select
                  mode="multiple"
                  placeholder={CREATE.STUDENTS_PLACEHOLDER}
                  className="min-h-11 w-full rounded-xl"
                  loading={loadingStudents}
                  options={studentOptions}
                  optionFilterProp="searchValue"
                  maxTagCount="responsive"
                  disabled={initialStudents.length > 0}
                />
              </Form.Item>
            )}
          </div>

          <CompoundModal.Footer
            cancelText={CREATE.CANCEL}
            confirmText={isEdit ? CREATE.SUBMIT_EDIT : CREATE.SUBMIT}
            onCancel={handleCancel}
            onConfirm={() => form.submit()}
            className="mt-8 pt-6"
          />
        </Form>
      </CompoundModal>
    );
  }
);
CreateGroupModal.displayName = 'CreateGroupModal';

export default CreateGroupModal;

'use client';

import { SearchOutlined, UserOutlined } from '@ant-design/icons';
import { Form, Input, Select } from 'antd';
import React, { useEffect } from 'react';

import CompoundModal from '@/components/ui/CompoundModal';
import { INTERNSHIP_MANAGEMENT_UI } from '@/constants/internship-management/internship-management';

import { useEnterpriseGroups } from '../../internship-group-management/hooks/useEnterpriseGroups';

const GroupActionModal = ({ open, students = [], type, onCancel, onConfirm }) => {
  const [form] = Form.useForm();
  const { GROUP_ACTION } = INTERNSHIP_MANAGEMENT_UI.INTERNSHIP_LIST.MODALS;

  useEffect(() => {
    if (open) form.resetFields();
  }, [open, form]);

  const { data: activeGroups, loading: fetchingGroups } = useEnterpriseGroups({
    termId: students[0]?.termId, // Use the first student's termId, mock will fall back if undefined
    filters: { status: 1 }, // Changed from 0 to 1 based on backend validation error
    pagination: { current: 1, pageSize: 100 }, // Fetch a large chunk for dropdown
    search: '',
  });

  const currentGroupIds = React.useMemo(() => {
    return students.map((s) => s.groupId).filter(Boolean);
  }, [students]);

  return (
    <CompoundModal open={open} onCancel={onCancel} width={560} destroyOnHidden>
      <CompoundModal.Header
        icon={<UserOutlined />}
        title={type === 'ADD' ? GROUP_ACTION.TITLE_ADD : GROUP_ACTION.TITLE_CHANGE}
        subtitle={
          <div className="flex items-center gap-2">
            <span className="opacity-70">{GROUP_ACTION.STUDENT_LABEL}</span>
            <span className="text-text font-bold">
              {students.length === 1
                ? students[0]?.studentFullName || students[0]?.fullName
                : `${students.length} students selected`}
            </span>
          </div>
        }
      />

      <Form
        form={form}
        layout="vertical"
        onFinish={onConfirm}
        className="p-6 pt-8"
        requiredMark={false}
      >
        <Form.Item
          label={
            <span className="text-text text-xs font-bold tracking-wider uppercase">
              {GROUP_ACTION.GROUP_LABEL}
            </span>
          }
          name="groupId"
          rules={[{ required: true, message: GROUP_ACTION.GROUP_REQUIRED }]}
        >
          <Select
            showSearch
            placeholder={GROUP_ACTION.GROUP_PLACEHOLDER}
            className="h-11 w-full rounded-xl"
            suffixIcon={<SearchOutlined className="text-muted" />}
            loading={fetchingGroups}
            options={activeGroups.map((g) => {
              const isCurrent = currentGroupIds.includes(g.id);
              return {
                label: (
                  <div className="flex justify-between items-center w-full">
                    <span>{`${g.name} \u2014 ${g.mentorName || 'No Mentor'} \u2014 ${g.memberCount} ${GROUP_ACTION.STUDENTS_SUFFIX}`}</span>
                    {isCurrent && (
                      <span className="bg-gray-100 text-muted px-2 py-0.5 rounded text-[10px] uppercase font-bold">
                        {'Current Group'}
                      </span>
                    )}
                  </div>
                ),
                value: g.id,
                disabled: isCurrent,
              };
            })}
            filterOption={(input, option) => {
              // Extract text from the complex label object for filtering
              const labelText = activeGroups.find((g) => g.id === option.value)?.name || '';
              return labelText.toLowerCase().includes(input.toLowerCase());
            }}
          />
        </Form.Item>

        {type === 'CHANGE' && (
          <Form.Item
            label={
              <span className="text-text text-xs font-bold tracking-wider uppercase">
                {GROUP_ACTION.REASON_LABEL}
              </span>
            }
            name="reason"
            rules={[{ required: true, message: GROUP_ACTION.REASON_REQUIRED }]}
          >
            <Input.TextArea
              rows={4}
              placeholder={GROUP_ACTION.REASON_PLACEHOLDER}
              className="bg-surface border-border rounded-xl px-4 py-3"
            />
          </Form.Item>
        )}

        <CompoundModal.Footer
          cancelText={GROUP_ACTION.CANCEL}
          submitText={type === 'ADD' ? GROUP_ACTION.SUBMIT_ADD : GROUP_ACTION.SUBMIT_CHANGE}
          onCancel={onCancel}
          onSubmit={() => form.submit()}
          className="mt-8 pt-6"
        />
      </Form>
    </CompoundModal>
  );
};

export default GroupActionModal;

'use client';

import {
  CheckOutlined,
  CloseOutlined,
  EyeOutlined,
  MoreOutlined,
  TeamOutlined,
  UserOutlined,
} from '@ant-design/icons';
import { Button, Dropdown } from 'antd';
import React, { memo, useMemo } from 'react';

import DataTable from '@/components/ui/datatable';
import { INTERNSHIP_MANAGEMENT_UI } from '@/constants/internship-management/internship-management';

import { MOCK_GROUPS, MOCK_MENTORS } from '../constants/internshipData';
import StatusTag from './StatusTag';

const InternshipTable = memo(function InternshipTable({
  data,
  loading,
  page,
  pageSize,
  onAccept,
  onReject,
  onAssign,
  onGroup,
  onView,
  selectedRowKeys = [],
  onSelectRowChange,
}) {
  const { TABLE, ACTIONS, STATUS_LABELS } = INTERNSHIP_MANAGEMENT_UI.INTERNSHIP_LIST;

  const rowSelection = {
    selectedRowKeys,
    onChange: onSelectRowChange,
  };

  const columns = useMemo(
    () => [
      {
        title: '#',
        key: 'index',
        width: '60px',
        align: 'center',
        render: (_, __, index) => (page - 1) * pageSize + index + 1,
        className: 'text-muted font-semibold text-xs',
      },
      {
        title: TABLE.COLUMNS.FULL_NAME,
        dataIndex: 'fullName',
        key: 'fullName',
        width: 160,
        render: (text, record) => {
          return (
            <div className="flex items-center gap-2">
              <div className="flex flex-col overflow-hidden">
                <span className="text-text truncate text-sm font-bold">{text || 'N/A'}</span>
                <span className="text-muted truncate text-[11px] font-medium tracking-wider uppercase opacity-60">
                  {record.major || 'None'}
                </span>
              </div>
            </div>
          );
        },
      },
      {
        title: TABLE.COLUMNS.STUDENT_ID,
        dataIndex: 'studentId',
        key: 'studentId',
        width: 70,
        render: (id) => (
          <span className="text-muted font-mono text-xs font-semibold uppercase">{id}</span>
        ),
      },
      {
        title: TABLE.COLUMNS.STATUS,
        dataIndex: 'status',
        key: 'status',
        width: 90,
        align: 'center',
        render: (status) => <StatusTag status={status} />,
      },
      {
        title: TABLE.COLUMNS.GROUP,
        dataIndex: 'groupId',
        key: 'group',
        width: 120,
        render: (id) => {
          const group = MOCK_GROUPS.find((g) => g.id === id);
          return group ? (
            <div className="flex items-center gap-1.5 overflow-hidden">
              <TeamOutlined className="text-primary text-xs opacity-60" />
              <span className="text-text truncate text-xs font-bold">{group.name}</span>
            </div>
          ) : (
            <span className="text-muted text-[10px] font-medium tracking-wider uppercase italic opacity-40">
              {TABLE.NOT_ASSIGNED}
            </span>
          );
        },
      },
      {
        title: TABLE.COLUMNS.MENTOR,
        dataIndex: 'mentorId',
        key: 'mentor',
        width: 120,
        render: (id) => {
          const mentor = MOCK_MENTORS.find((m) => m.id === id);
          return mentor ? (
            <div className="flex items-center gap-1.5 overflow-hidden">
              <div className="bg-primary-hover h-1.5 w-1.5 shrink-0 rounded-full" />
              <span className="text-text truncate text-xs font-bold">{mentor.name}</span>
            </div>
          ) : (
            <span className="text-muted text-[10px] font-medium tracking-wider uppercase italic opacity-40">
              {TABLE.NOT_ASSIGNED}
            </span>
          );
        },
      },
      {
        title: TABLE.COLUMNS.ACTION,
        key: 'actions',
        width: 40,
        align: 'center',
        render: (_, record) => {
          const items = [
            {
              key: 'view',
              label: ACTIONS.VIEW_BIO,
              icon: <EyeOutlined className="text-primary" />,
              onClick: () => onView(record),
            },
            { type: 'divider' },
            ...(record.status === 'PENDING'
              ? [
                  {
                    key: 'accept',
                    label: ACTIONS.ACCEPT,
                    icon: <CheckOutlined className="text-success" />,
                    onClick: () => onAccept(record),
                  },
                  {
                    key: 'reject',
                    label: ACTIONS.REJECT,
                    icon: <CloseOutlined className="text-danger" />,
                    onClick: () => onReject(record),
                  },
                  { type: 'divider' },
                ]
              : []),
            {
              key: 'assign',
              label: ACTIONS.ASSIGN,
              icon: <UserOutlined className="text-primary" />,
              onClick: () => onAssign(record),
            },
            {
              key: 'group',
              label: ACTIONS.ADD_TO_GROUP,
              icon: <TeamOutlined className="text-primary" />,
              onClick: () => onGroup(record),
            },
          ];

          return (
            <div onClick={(e) => e.stopPropagation()}>
              <Dropdown menu={{ items }} trigger={['click']} placement="bottomRight">
                <Button
                  type="text"
                  size="small"
                  icon={<MoreOutlined />}
                  className="hover:bg-primary/10 text-muted flex h-8 w-8 items-center justify-center rounded-lg"
                />
              </Dropdown>
            </div>
          );
        },
      },
    ],
    [page, pageSize, onAccept, onReject, onAssign, onGroup, onView, TABLE, ACTIONS]
  );

  return (
    <DataTable
      columns={columns}
      data={data}
      loading={loading}
      rowKey="id"
      rowSelection={rowSelection}
      minWidth="780px"
      tableLayout="fixed"
      className="no-scrollbar mt-2 min-h-0 flex-1"
      onRowClick={onView}
    />
  );
});

export default InternshipTable;

'use client';

import { UserOutlined } from '@ant-design/icons';
import { Descriptions, Typography } from 'antd';
import React from 'react';

import CompoundModal from '@/components/ui/CompoundModal';
import { INTERNSHIP_MANAGEMENT_UI } from '@/constants/internship-management/internship-management';

import StatusTag from './StatusTag';

const { Text } = Typography;

const StudentDetailModal = ({ open, student, onCancel }) => {
  const { INTERNSHIP_LIST } = INTERNSHIP_MANAGEMENT_UI;
  const { DETAIL } = INTERNSHIP_LIST.MODALS;

  if (!student) return null;

  const statusMap = {
    1: 'PENDING',
    2: 'ACCEPTED',
    3: 'REJECTED',
  };
  const displayStatus = statusMap[student.status] || 'PENDING';

  return (
    <CompoundModal open={open} onCancel={onCancel} width={500} destroyOnHidden footer={null}>
      <CompoundModal.Header
        icon={<UserOutlined />}
        title={student.studentFullName}
        subtitle={student.studentCode}
      />

      <div className="px-10 pb-6 pt-4">
        <Descriptions
          column={1}
          size="small"
          layout="horizontal"
          bordered={false}
          labelStyle={{
            color: 'rgba(0,0,0,0.45)',
            fontWeight: 600,
            fontSize: '11px',
            textTransform: 'uppercase',
            width: '120px',
          }}
          contentStyle={{ fontWeight: 700, fontSize: '13px', color: '#1f1f1f' }}
        >
          <Descriptions.Item label={DETAIL.STATUS}>
            <StatusTag status={displayStatus} />
          </Descriptions.Item>
          <Descriptions.Item label={DETAIL.MAJOR}>{student.major || '-'}</Descriptions.Item>
          <Descriptions.Item label={DETAIL.UNIVERSITY}>
            {student.universityName || '-'}
          </Descriptions.Item>
          <Descriptions.Item label={DETAIL.EMAIL}>{student.studentEmail || '-'}</Descriptions.Item>
          <Descriptions.Item label={DETAIL.PHONE}>
            {student.phone || '098-XXX-XXXX'}
          </Descriptions.Item>
          <Descriptions.Item label={DETAIL.DOB}>{student.dob || '01/01/2002'}</Descriptions.Item>
          <Descriptions.Item label={DETAIL.GROUP}>{student.groupName || '-'}</Descriptions.Item>
          <Descriptions.Item label={DETAIL.MENTOR}>{student.mentorName || '-'}</Descriptions.Item>
          <Descriptions.Item label={DETAIL.PROJECT}>
            {student.projectName || student.track || '-'}
          </Descriptions.Item>
        </Descriptions>

        <div className="mt-4 flex justify-end text-[10px] uppercase tracking-wider text-muted italic opacity-30">
          {DETAIL.PLACEMENT_DATE}:{' '}
          {student.appliedAt ? new Date(student.appliedAt).toLocaleDateString('en-GB') : '-'}
        </div>
      </div>
    </CompoundModal>
  );
};

export default StudentDetailModal;

import { useCallback, useEffect, useState } from 'react';

import { useToast } from '@/providers/ToastProvider';

import { ENTERPRISE_STUDENT_UI } from '../constants/enterprise-student.constants';
import { EnterpriseStudentService } from '../services/enterprise-student.service';

export const useEnterpriseStudents = ({ termId, filters, search, pagination, sort }) => {
  const toast = useToast();
  const [data, setData] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(false);

  const fetchStudents = useCallback(async () => {
    if (!termId) return;

    try {
      setLoading(true);
      const params = {
        PageIndex: pagination.current,
        PageSize: pagination.pageSize,
        SearchTerm: search || undefined,
        Search: search || undefined,
        Status:
          filters.status !== undefined ? (filters.status === 'ALL' ? null : filters.status) : null,
        // camelCase just in case
        termId,
        TermId: termId,
        pageIndex: pagination.current,
        pageSize: pagination.pageSize,
        searchTerm: search || undefined,
        status:
          filters.status !== undefined ? (filters.status === 'ALL' ? null : filters.status) : null,
        mentorAssigned: filters.mentorAssigned,
        SortColumn: sort?.column,
        SortOrder: sort?.order,
      };

      const response = await EnterpriseStudentService.getApplications(params);

      if (response?.data?.items) {
        setData(response.data.items.map(EnterpriseStudentService.mapApplication));
        setTotal(response.data.totalCount || 0);
      } else {
        setData([]);
        setTotal(0);
      }
    } catch (error) {
      console.error('Fetch Enterprise Students Error:', error);
      toast.error(ENTERPRISE_STUDENT_UI.MESSAGES.LOAD_ERROR);
      setData([]);
      setTotal(0);
    } finally {
      setLoading(false);
    }
  }, [
    termId,
    pagination,
    search,
    filters?.status,
    filters?.mentorAssigned,
    filters?.hasGroup,
    sort?.column,
    sort?.order,
    toast,
  ]);

  useEffect(() => {
    fetchStudents();
  }, [fetchStudents]);

  return {
    data,
    total,
    loading,
    refetch: fetchStudents,
  };
};
